// ---------------------------------------------------------------------------

#[test]
fn rprop_plain_step_parity() {
    let fix = load_fixtures();
    let variant = fix["rprop"]
        .as_array()
        .unwrap()
        .iter()
        .find(|v| v["variant"] == "plain")
        .expect("rprop plain fixture");

    let lr = variant["lr"].as_f64().unwrap();
    let etas = variant["etas"].as_array().unwrap();
    let eta_minus = etas[0].as_f64().unwrap();
    let eta_plus = etas[1].as_f64().unwrap();
    let sr = variant["step_sizes_range"].as_array().unwrap();
    let step_min = sr[0].as_f64().unwrap();
    let step_max = sr[1].as_f64().unwrap();

    let init = init_params_f32();
    let grads = grad_steps_f32();

    let param = make_param(&init);
    let config = RpropConfig::default()
        .with_lr(lr)
        .with_etas((eta_minus, eta_plus))
        .with_step_sizes((step_min, step_max));
    let mut opt = Rprop::new(vec![param.clone()], config);

    let steps = variant["steps"].as_array().unwrap();
    for (i, step_fix) in steps.iter().enumerate() {
        set_grad(&param, &grads[i]);
        opt.step().unwrap();
        let actual = read_param(&param);
        let expected: Vec<f32> = fvec(&step_fix["params"]);
        assert_close_vec(
            &actual,
            &expected,
            TOL,
            &format!("rprop_plain step {}", i + 1),
        );
    }
}

